SELECT department_id, birth_rate
FROM demographic_indicators
WHERE year = 2001 AND source = 'census';

SELECT d.department_name, y.total_population, y.average_population_growth, y.source
FROM departments d
JOIN yearly_data y ON y.year = 2001;

SELECT urban_population 
FROM urbanization 
WHERE department_id = 1 AND year = 2001;

SELECT d.department_name
FROM departments d
JOIN (
    SELECT department_id
    FROM population_data
    WHERE population = (
        SELECT MAX(population)
        FROM population_data
    )
) pd ON d.department_id = pd.department_id;
